        "front": "What is a game engine?",
        "back": "A game engine is software that provides the framework for game development.",
        "icon": "engine"
      },
      {
        "front": "What does 'game mechanics' refer to?",
        "back": "Game mechanics are the rules and systems that govern gameplay.",
        "icon": "mechanics"
      },
      {
        "front": "What is 'level design'?",
        "back": "Level design is the process of creating the environments and challenges in a game.",
        "icon": "design"
      },
      {
        "front": "What is 'game loop'?",
        "back": "A game loop is the cycle that keeps the game running, processing inputs and updating the game state.",
        "icon": "loop"
      }
    ]
  }
